class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> list:
        n = len(s)
        la, lb = len(a), len(b)
        a_pos = [i for i in range(n - la + 1) if s[i:i+la] == a]
        b_pos = [i for i in range(n - lb + 1) if s[i:i+lb] == b]
        result = []
        for i in a_pos:
            if any(abs(i - j) <= k for j in b_pos):
                result.append(i)
        return result

