class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> list:
        import bisect
        def kmp_search(text, pat):
            if not pat:
                return list(range(len(text)))
            n, m = len(text), len(pat)
            fail = [0] * m
            j = 0
            for i in range(1, m):
                while j and pat[i] != pat[j]:
                    j = fail[j-1]
                if pat[i] == pat[j]:
                    j += 1
                fail[i] = j
            res, j = [], 0
            for i in range(n):
                while j and text[i] != pat[j]:
                    j = fail[j-1]
                if text[i] == pat[j]:
                    j += 1
                if j == m:
                    res.append(i - m + 1)
                    j = fail[j-1]
            return res
        a_pos = kmp_search(s, a)
        b_pos = kmp_search(s, b)
        result = []
        for i in a_pos:
            lo = bisect.bisect_left(b_pos, i - k)
            if lo < len(b_pos) and b_pos[lo] <= i + k:
                result.append(i)
        return result

