var beautifulIndices = function(s, a, b, k) {
    function kmpSearch(text, pat) {
        const n = text.length, m = pat.length;
        if (m === 0) return Array.from({length: n}, (_, i) => i);
        const fail = new Array(m).fill(0);
        let j = 0;
        for (let i = 1; i < m; i++) {
            while (j && pat[i] !== pat[j]) j = fail[j-1];
            if (pat[i] === pat[j]) j++;
            fail[i] = j;
        }
        const res = []; j = 0;
        for (let i = 0; i < n; i++) {
            while (j && text[i] !== pat[j]) j = fail[j-1];
            if (text[i] === pat[j]) j++;
            if (j === m) { res.push(i - m + 1); j = fail[j-1]; }
        }
        return res;
    }
    function bisectLeft(arr, val) {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo+hi)>>1; if (arr[mid] < val) lo = mid+1; else hi = mid; }
        return lo;
    }
    const aPos = kmpSearch(s, a);
    const bPos = kmpSearch(s, b);
    const result = [];
    for (const i of aPos) {
        const lo = bisectLeft(bPos, i - k);
        if (lo < bPos.length && bPos[lo] <= i + k) result.push(i);
    }
    return result;
};
